import React, { useState, useEffect } from 'react';
import { LogOut, User, Bell, Search, ChevronDown, Briefcase, LayoutDashboard, Loader2, Globe, Lock, TrendingUp, PieChart, AlertCircle, Sparkles, MapPin, ArrowRight, Calendar, Users } from 'lucide-react';
import { Student, JobPosting } from '../types';
import EmploymentStatusPage from './EmploymentStatusPage';
import MyProfilePage from './MyProfilePage';
import JobPostingsPage from './JobPostingsPage';
import ForYouPage from './ForYouPage';
import ConnectPage from './ConnectPage';
import { fetchLatestProfile } from '../services/resumeService';
import { getOpenJobs } from '../services/jobService';
import { supabase } from '../lib/supabaseClient';

interface DashboardProps {
  user: Student;
  onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState<'home' | 'employment' | 'profile' | 'jobs' | 'for-you' | 'connect'>('home');
  const [loadingMetrics, setLoadingMetrics] = useState(true);

  // Data State
  const [recentJobs, setRecentJobs] = useState<JobPosting[]>([]);

  // Restriction State
  const [showRestrictionModal, setShowRestrictionModal] = useState(false);

  // Dashboard Metrics State
  const [metrics, setMetrics] = useState({
    completionPercentage: 0,
    employmentStatus: 'Unknown',
    latestCompany: '',
    missingSections: [] as string[]
  });

  useEffect(() => {
    const loadDashboardData = async () => {
        if (!user.id) return;
        setLoadingMetrics(true);
        try {
            // Determine table
            const userType = user.table_source === 'students' ? 'student' : 
                             user.table_source === 'alumni' ? 'alumni' : 
                             (user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni');

            // 1. Fetch Profile Data
            const profileData = await fetchLatestProfile(user.id, userType);

            // 2. Fetch Employment Records
            const idColumn = userType === 'alumni' ? 'alumni_id' : 'student_id';
            const { data: surveys } = await supabase.from('survey_responses').select('id').eq(idColumn, user.id);

            let statusDisplay = 'Update Status';
            let companyDisplay = '';

            if (surveys && surveys.length > 0) {
                const surveyIds = surveys.map(s => s.id);
                const { data: records } = await supabase
                    .from('employment_information')
                    .select('*')
                    .in('survey_response_id', surveyIds)
                    .order('id', { ascending: false });

                if (records && records.length > 0) {
                    const hasEmployed = records.some(r => r.employment_status === 'Employed');
                    const hasSelfEmployed = records.some(r => r.employment_status === 'Self-employed');
                    const latest = records[0];

                    if (hasEmployed && hasSelfEmployed) {
                        statusDisplay = 'Employed & Self-employed';
                        companyDisplay = 'Multiple Roles';
                    } else if (hasEmployed) {
                        statusDisplay = 'Employed';
                        companyDisplay = latest.company_name;
                    } else if (hasSelfEmployed) {
                        statusDisplay = 'Self-employed';
                        companyDisplay = latest.business_name;
                    } else {
                        statusDisplay = latest.employment_status || 'Unknown';
                        if (statusDisplay === 'Retired') companyDisplay = `Retired from ${latest.last_company || 'work'}`;
                        else companyDisplay = 'Not currently employed';
                    }
                }
            }

            // 3. Completion Percentage
            let score = 0;
            const missing: string[] = [];

            if (user.address && user.contact_no) score += 25;
            else missing.push("Contact Details");

            if (statusDisplay !== 'Update Status' && statusDisplay !== 'Unknown') score += 25;
            else missing.push("Employment Status");

            if (profileData && profileData.education && (profileData.education.primary_school || profileData.education.bachelors_degree)) score += 25;
            else missing.push("Education History");

            const hasAttributes = profileData && profileData.attributes && Object.values(profileData.attributes).some(val => Number(val) > 0);
            if (hasAttributes) score += 25;
            else missing.push("Skills & Attributes");

            setMetrics({
                completionPercentage: score,
                employmentStatus: statusDisplay,
                latestCompany: companyDisplay,
                missingSections: missing
            });

            // 4. Fetch Recent Jobs (for widget)
            const jobs = await getOpenJobs();
            setRecentJobs(jobs.slice(0, 2)); // Get top 2 newest

        } catch (error) {
            console.error("Dashboard Load Error", error);
        } finally {
            setLoadingMetrics(false);
        }
    };

    if (activeTab === 'home') {
        loadDashboardData();
    }
  }, [user.id, user.enrollment_status, activeTab, user.table_source]);

  const handleRestrictedTab = (tab: 'jobs' | 'for-you' | 'connect') => {
      if (metrics.completionPercentage < 100) {
          setShowRestrictionModal(true);
      } else {
          setActiveTab(tab);
      }
  };

  const NavItem = ({ id, label, icon: Icon, locked = false }: { id: string, label: string, icon: any, locked?: boolean }) => (
    <button 
      onClick={() => locked ? handleRestrictedTab(id as any) : setActiveTab(id as any)}
      className={`w-full flex items-center justify-between px-4 py-3.5 rounded-2xl transition-all duration-300 group relative overflow-hidden ${
        activeTab === id 
        ? 'bg-gradient-to-r from-luGreen to-emerald-600 text-white shadow-lg shadow-green-500/20' 
        : 'text-gray-600 hover:bg-white/50 hover:text-luGreen'
      }`}
    >
        <div className="flex items-center gap-3 relative z-10">
            <Icon size={20} className={activeTab === id ? 'text-white' : 'text-gray-400 group-hover:text-luGreen'} />
            <span className="font-bold text-sm tracking-wide">{label}</span>
        </div>
        {locked && metrics.completionPercentage < 100 && (
            <Lock size={14} className="text-gray-400/70" />
        )}
        {activeTab === id && (
            <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
        )}
    </button>
  );

  return (
    <div className="min-h-screen bg-[#f0f4f8] flex flex-col font-sans relative overflow-x-hidden text-slate-800">

      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none">
          <div className="absolute -top-[20%] -left-[10%] w-[70%] h-[70%] rounded-full bg-green-200/20 blur-[120px]"></div>
          <div className="absolute top-[20%] -right-[10%] w-[60%] h-[60%] rounded-full bg-yellow-200/20 blur-[120px]"></div>
          <div className="absolute -bottom-[10%] left-[20%] w-[50%] h-[50%] rounded-full bg-emerald-200/20 blur-[120px]"></div>
      </div>

      {/* Glass Header */}
      <header className="sticky top-0 z-50 transition-all duration-300 px-4 pt-4">
        <div className="bg-white/70 backdrop-blur-xl border border-white/50 shadow-sm rounded-3xl px-6 py-4 flex justify-between items-center max-w-[1600px] mx-auto">

            {/* Logo */}
            <div className="flex items-center space-x-3 cursor-pointer" onClick={() => setActiveTab('home')}>
              <div className="w-10 h-10 bg-gradient-to-br from-luGreen to-emerald-600 rounded-xl flex items-center justify-center shadow-lg text-white font-display font-bold text-lg">
                 LU
              </div>
              <div className="hidden md:block">
                <h1 className="text-lg font-bold text-slate-800 tracking-tight leading-none">ALUMNI TRACER</h1>
                <p className="text-[10px] text-slate-500 font-bold tracking-widest uppercase mt-0.5">Laguna University</p>
              </div>
            </div>

            {/* Right Actions */}
            <div className="flex items-center gap-4">
              <div className="hidden md:flex items-center space-x-2 text-xs bg-emerald-50/80 backdrop-blur-md text-emerald-700 py-1.5 px-3 rounded-full border border-emerald-100/50">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
                </span>
                <span className="font-bold">System Online</span>
              </div>

              <div className="h-8 w-[1px] bg-slate-200/50 hidden md:block"></div>

              <div className="flex items-center gap-3">
                  <div className="text-right hidden sm:block">
                      <p className="text-sm font-bold text-slate-800 leading-none">{user.first_name} {user.last_name}</p>
                      <p className="text-[10px] text-slate-500 font-bold uppercase mt-0.5">{user.program}</p>
                  </div>
                  <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-slate-200 to-slate-100 border-2 border-white shadow-md flex items-center justify-center text-slate-600 font-bold">
                      {user.first_name[0]}
                  </div>
                  <button 
                    onClick={onLogout}
                    className="p-2.5 bg-white/50 hover:bg-red-50 text-slate-400 hover:text-red-500 rounded-xl transition-all border border-transparent hover:border-red-100"
                    title="Sign Out"
                  >
                    <LogOut size={18} />
                  </button>
              </div>
            </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow w-full max-w-[1600px] mx-auto px-4 py-6 relative z-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

          {/* Left Navigation Panel */}
          <div className="lg:col-span-3">
            <div className="bg-white/40 backdrop-blur-xl rounded-[2rem] border border-white/50 shadow-xl shadow-slate-200/50 p-4 sticky top-28">
                <div className="px-4 py-3">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Main Menu</p>
                    <div className="space-y-1">
                        <NavItem id="home" label="Dashboard" icon={LayoutDashboard} />
                        <NavItem id="profile" label="My Profile" icon={User} />
                        <NavItem id="employment" label="Job Status" icon={Briefcase} />
                    </div>
                </div>

                <div className="px-4 py-3 mt-2">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Opportunities</p>
                    <div className="space-y-1">
                        <NavItem id="connect" label="Network" icon={Globe} locked />
                        <NavItem id="jobs" label="Job Board" icon={Briefcase} locked />
                        <NavItem id="for-you" label="For You" icon={Sparkles} locked />
                    </div>
                </div>

                <div className="mt-6 p-4 bg-gradient-to-br from-luGreen/10 to-emerald-100/50 rounded-2xl border border-white/50">
                    <div className="flex items-center gap-3 mb-2">
                        <div className="p-2 bg-white rounded-lg shadow-sm text-luGreen">
                            <TrendingUp size={16}/>
                        </div>
                        <span className="text-xs font-bold text-slate-700">Profile Strength</span>
                    </div>
                    <div className="w-full h-1.5 bg-white/50 rounded-full overflow-hidden mb-2">
                        <div 
                            className={`h-full rounded-full transition-all duration-1000 ${metrics.completionPercentage === 100 ? 'bg-luGreen' : 'bg-amber-400'}`} 
                            style={{ width: `${metrics.completionPercentage}%` }}
                        ></div>
                    </div>
                    <p className="text-[10px] text-slate-500 font-medium">
                        {metrics.completionPercentage === 100 ? "Excellent! You're all set." : "Complete your profile to unlock features."}
                    </p>
                </div>
            </div>
          </div>

          {/* Right Content Area */}
          <div className="lg:col-span-9">

            {activeTab === 'home' && (
                <div className="space-y-6 animate-fade-in">

                    {/* Welcome Hero */}
                    <div className="relative rounded-[2.5rem] overflow-hidden bg-gradient-to-r from-slate-900 to-slate-800 text-white shadow-2xl shadow-slate-200/50 min-h-[220px] flex items-center">
                        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                        <div className="absolute right-0 top-0 w-96 h-96 bg-luGreen/20 rounded-full blur-[80px] -translate-y-1/2 translate-x-1/2"></div>

                        <div className="relative z-10 px-10 py-8 w-full">
                            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
                                <div>
                                    <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/10 border border-white/10 text-[10px] font-bold uppercase tracking-wider mb-3 backdrop-blur-md">
                                        <Sparkles size={10} className="text-yellow-400"/> Welcome Back
                                    </div>
                                    <h2 className="text-3xl md:text-4xl font-display font-bold mb-2">Hello, {user.first_name}!</h2>
                                    <p className="text-slate-300 text-sm max-w-lg leading-relaxed">
                                        Stay connected with your alma mater. Update your career progress and discover new opportunities tailored for you.
                                    </p>
                                </div>
                                <div className="hidden md:block">
                                    {/* Abstract Decoration */}
                                    <div className="w-24 h-24 rounded-2xl bg-gradient-to-tr from-luGreen to-emerald-400 opacity-80 rotate-12 blur-sm"></div>
                                    <div className="w-24 h-24 rounded-2xl bg-white/10 border border-white/20 absolute right-12 top-1/2 -translate-y-1/2 backdrop-blur-md"></div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Metrics Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Status Card */}
                        <div className="bg-white/60 backdrop-blur-xl p-6 rounded-[2rem] border border-white/60 shadow-lg shadow-slate-200/50 hover:bg-white/80 transition-all group">
                            <div className="flex justify-between items-start mb-6">
                                <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl group-hover:scale-110 transition-transform">
                                    <Briefcase size={24} />
                                </div>
                                <button onClick={() => setActiveTab('employment')} className="text-xs font-bold text-slate-400 hover:text-blue-600 flex items-center gap-1">
                                    Update <ArrowRight size={12}/>
                                </button>
                            </div>
                            <div>
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Employment Status</p>
                                <h3 className={`text-2xl font-black ${metrics.employmentStatus === 'Unemployed' ? 'text-red-500' : 'text-slate-800'}`}>
                                    {loadingMetrics ? 'Loading...' : metrics.employmentStatus}
                                </h3>
                                <p className="text-sm font-medium text-slate-500 mt-1 truncate">
                                    {metrics.latestCompany || 'No active employment record'}
                                </p>
                            </div>
                        </div>

                        {/* Completion Card */}
                        <div className="bg-white/60 backdrop-blur-xl p-6 rounded-[2rem] border border-white/60 shadow-lg shadow-slate-200/50 hover:bg-white/80 transition-all group">
                            <div className="flex justify-between items-start mb-6">
                                <div className={`p-3 rounded-2xl group-hover:scale-110 transition-transform ${metrics.completionPercentage === 100 ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                                    <PieChart size={24} />
                                </div>
                                <button onClick={() => setActiveTab('profile')} className="text-xs font-bold text-slate-400 hover:text-emerald-600 flex items-center gap-1">
                                    Edit Profile <ArrowRight size={12}/>
                                </button>
                            </div>
                            <div>
                                <div className="flex justify-between items-end mb-1">
                                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Profile Completion</p>
                                    <span className="text-xl font-black text-slate-800">{metrics.completionPercentage}%</span>
                                </div>
                                <div className="w-full h-2 bg-slate-100 rounded-full overflow-hidden">
                                    <div 
                                        className={`h-full rounded-full transition-all duration-1000 ${metrics.completionPercentage === 100 ? 'bg-emerald-500' : 'bg-amber-400'}`} 
                                        style={{ width: `${metrics.completionPercentage}%` }}
                                    ></div>
                                </div>
                                {metrics.missingSections.length > 0 && (
                                    <div className="mt-3 flex items-center gap-2">
                                        <AlertCircle size={12} className="text-amber-500" />
                                        <p className="text-[10px] font-bold text-amber-600">
                                            Missing: {metrics.missingSections[0]} {metrics.missingSections.length > 1 && `+${metrics.missingSections.length - 1} more`}
                                        </p>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                        {/* Latest Jobs Widget (Locked if < 100%) */}
                        <div className="lg:col-span-2 bg-white/60 backdrop-blur-xl p-6 rounded-[2rem] border border-white/60 shadow-lg shadow-slate-200/50 relative overflow-hidden flex flex-col">
                            <div className="flex justify-between items-center mb-6">
                                <h3 className="font-bold text-lg text-slate-800">Recommended Opportunities</h3>
                                {metrics.completionPercentage === 100 && (
                                    <button onClick={() => setActiveTab('jobs')} className="text-xs font-bold text-luGreen hover:underline">View All</button>
                                )}
                            </div>

                            {/* Conditional Content */}
                            {metrics.completionPercentage < 100 ? (
                                <div className="flex-grow flex flex-col items-center justify-center text-center py-8 relative">
                                    {/* Blurred Background Mockup */}
                                    <div className="absolute inset-0 bg-white/40 backdrop-blur-md z-10 flex items-center justify-center rounded-2xl">
                                        <div className="bg-white/80 p-6 rounded-2xl shadow-xl border border-white flex flex-col items-center">
                                            <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-400 mb-3">
                                                <Lock size={24} />
                                            </div>
                                            <h4 className="font-bold text-gray-800 mb-1">Feature Locked</h4>
                                            <p className="text-xs text-gray-500 max-w-[200px]">Complete your profile to 100% to unlock personalized job recommendations.</p>
                                            <button onClick={() => setActiveTab('profile')} className="mt-4 px-4 py-2 bg-gray-900 text-white text-xs font-bold rounded-lg hover:bg-black transition-colors">
                                                Complete Profile
                                            </button>
                                        </div>
                                    </div>
                                    {/* Fake Content Behind Blur */}
                                    <div className="w-full space-y-3 opacity-30 pointer-events-none filter blur-sm">
                                        <div className="h-20 bg-gray-200 rounded-xl w-full"></div>
                                        <div className="h-20 bg-gray-200 rounded-xl w-full"></div>
                                    </div>
                                </div>
                            ) : (
                                <div className="space-y-3">
                                    {recentJobs.length === 0 ? (
                                        <div className="text-center py-10 text-gray-400 text-sm">No new jobs available.</div>
                                    ) : (
                                        recentJobs.map(job => (
                                            <div key={job.id} className="p-4 bg-white rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all flex justify-between items-center group">
                                                <div className="flex items-center gap-4">
                                                    <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center font-bold">
                                                        {job.company_name[0]}
                                                    </div>
                                                    <div>
                                                        <h4 className="font-bold text-gray-800 text-sm group-hover:text-blue-600 transition-colors">{job.job_title}</h4>
                                                        <p className="text-xs text-gray-500">{job.company_name} • {job.location}</p>
                                                    </div>
                                                </div>
                                                <button onClick={() => setActiveTab('jobs')} className="p-2 bg-gray-50 text-gray-400 rounded-lg group-hover:bg-blue-600 group-hover:text-white transition-colors">
                                                    <ArrowRight size={16} />
                                                </button>
                                            </div>
                                        ))
                                    )}
                                </div>
                            )}
                        </div>

                        {/* Networking Widget */}
                        <div className="bg-gradient-to-b from-indigo-600 to-purple-700 p-6 rounded-[2rem] shadow-xl text-white relative overflow-hidden flex flex-col justify-between min-h-[250px]">
                            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-3xl"></div>
                            <div className="relative z-10">
                                <div className="flex items-center gap-2 mb-4">
                                    <div className="p-2 bg-white/20 rounded-lg backdrop-blur-sm"><Users size={18}/></div>
                                    <span className="text-xs font-bold uppercase tracking-widest text-indigo-100">Community</span>
                                </div>
                                <h3 className="text-xl font-bold mb-2">Expand Your Network</h3>
                                <p className="text-indigo-100 text-xs leading-relaxed mb-6">
                                    Connect with fellow graduates, join forums, and create groups.
                                </p>
                            </div>

                            <button 
                                onClick={() => metrics.completionPercentage < 100 ? setShowRestrictionModal(true) : setActiveTab('connect')}
                                className="w-full py-3 bg-white text-indigo-600 font-bold rounded-xl shadow-lg hover:bg-indigo-50 transition-colors flex items-center justify-center gap-2 text-sm relative z-10"
                            >
                                <Globe size={16}/> Go to Connect
                            </button>
                        </div>
                    </div>

                </div>
            )}

            {activeTab === 'profile' && (
                <div className="bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-xl shadow-slate-200/50 p-6 md:p-8 animate-fade-in">
                    <MyProfilePage user={user} />
                </div>
            )}

            {activeTab === 'employment' && (
                <EmploymentStatusPage user={user} />
            )}

            {activeTab === 'jobs' && (
                <div className="bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-xl shadow-slate-200/50 p-6 md:p-8 animate-fade-in">
                    <JobPostingsPage user={user} />
                </div>
            )}

            {activeTab === 'for-you' && (
                <div className="bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-xl shadow-slate-200/50 p-6 md:p-8 animate-fade-in">
                    <ForYouPage user={user} />
                </div>
            )}

            {activeTab === 'connect' && (
                <div className="bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-xl shadow-slate-200/50 p-6 md:p-8 animate-fade-in min-h-[600px]">
                    <ConnectPage user={user} />
                </div>
            )}

          </div>
        </div>
      </main>

      {/* --- RESTRICTION MODAL --- */}
      {showRestrictionModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setShowRestrictionModal(false)}></div>
              <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20 p-8 text-center">
                  <div className="w-20 h-20 bg-amber-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner ring-8 ring-amber-50/50">
                      <Lock className="w-10 h-10 text-amber-500" />
                  </div>
                  <h3 className="text-2xl font-black text-gray-800 mb-2">Feature Locked</h3>
                  <p className="text-gray-500 text-sm mb-8 leading-relaxed">
                      This feature is reserved for active alumni with a complete profile. Please reach <strong>100% Profile Completion</strong> to access the network and job board.
                  </p>

                  <div className="space-y-3">
                      <button 
                          onClick={() => { setShowRestrictionModal(false); setActiveTab('profile'); }}
                          className="w-full py-4 bg-luGreen text-white font-bold rounded-2xl shadow-lg hover:bg-luGreen-dark transition-all text-sm flex items-center justify-center gap-2 hover:-translate-y-1"
                      >
                          Complete My Profile
                      </button>
                      <button 
                          onClick={() => setShowRestrictionModal(false)}
                          className="w-full py-4 bg-gray-100 text-gray-600 font-bold rounded-2xl hover:bg-gray-200 transition-colors text-sm"
                      >
                          Close
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { LogOut, User, Bell, Search, ChevronDown, Briefcase, LayoutDashboard, Loader2, Globe, Lock, PieChart, AlertCircle, Sparkles, MapPin, ArrowRight, Calendar, Users } from 'lucide-react';
import { Student, JobPosting } from '../types';
import EmploymentStatusPage from './EmploymentStatusPage';
import MyProfilePage from './MyProfilePage';
import JobPostingsPage from './JobPostingsPage';
import ForYouPage from './ForYouPage';
import ConnectPage from './ConnectPage';
import { fetchLatestProfile } from '../services/resumeService';
import { getOpenJobs } from '../services/jobService';
import { supabase } from '../lib/supabaseClient';

interface DashboardProps {
  user: Student;
  onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState<'home' | 'employment' | 'profile' | 'jobs' | 'for-you' | 'connect'>('home');
  const [loadingMetrics, setLoadingMetrics] = useState(true);

  // Data State
  const [recentJobs, setRecentJobs] = useState<JobPosting[]>([]);

  // Restriction State
  const [showRestrictionModal, setShowRestrictionModal] = useState(false);

  // Dashboard Metrics State
  const [metrics, setMetrics] = useState({
    completionPercentage: 0,
    employmentStatus: 'Unknown',
    latestCompany: '',
    missingSections: [] as string[]
  });

  useEffect(() => {
    const loadDashboardData = async () => {
        if (!user.id) return;
        setLoadingMetrics(true);
        try {
            // Determine table
            const userType = user.table_source === 'students' ? 'student' : 
                             user.table_source === 'alumni' ? 'alumni' : 
                             (user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni');

            // 1. Fetch Profile Data
            const profileData = await fetchLatestProfile(user.id, userType);

            // 2. Fetch Employment Records
            const idColumn = userType === 'alumni' ? 'alumni_id' : 'student_id';
            const { data: surveys } = await supabase.from('survey_responses').select('id').eq(idColumn, user.id);

            let statusDisplay = 'Update Status';
            let companyDisplay = '';

            if (surveys && surveys.length > 0) {
                const surveyIds = surveys.map(s => s.id);
                const { data: records } = await supabase
                    .from('employment_information')
                    .select('*')
                    .in('survey_response_id', surveyIds)
                    .order('id', { ascending: false });

                if (records && records.length > 0) {
                    const hasEmployed = records.some(r => r.employment_status === 'Employed');
                    const hasSelfEmployed = records.some(r => r.employment_status === 'Self-employed');
                    const latest = records[0];

                    if (hasEmployed && hasSelfEmployed) {
                        statusDisplay = 'Employed & Self-employed';
                        companyDisplay = 'Multiple Roles';
                    } else if (hasEmployed) {
                        statusDisplay = 'Employed';
                        companyDisplay = latest.company_name;
                    } else if (hasSelfEmployed) {
                        statusDisplay = 'Self-employed';
                        companyDisplay = latest.business_name;
                    } else {
                        statusDisplay = latest.employment_status || 'Unknown';
                        if (statusDisplay === 'Retired') companyDisplay = `Retired from ${latest.last_company || 'work'}`;
                        else companyDisplay = 'Not currently employed';
                    }
                }
            }

            // 3. Completion Percentage
            let score = 0;
            const missing: string[] = [];

            if (user.address && user.contact_no) score += 25;
            else missing.push("Contact Details");

            if (statusDisplay !== 'Update Status' && statusDisplay !== 'Unknown') score += 25;
            else missing.push("Employment Status");

            if (profileData && profileData.education && (profileData.education.primary_school || profileData.education.bachelors_degree)) score += 25;
            else missing.push("Education History");

            const hasAttributes = profileData && profileData.attributes && Object.values(profileData.attributes).some(val => Number(val) > 0);
            if (hasAttributes) score += 25;
            else missing.push("Skills & Attributes");

            setMetrics({
                completionPercentage: score,
                employmentStatus: statusDisplay,
                latestCompany: companyDisplay,
                missingSections: missing
            });

            // 4. Fetch Recent Jobs (for widget)
            const jobs = await getOpenJobs();
            setRecentJobs(jobs.slice(0, 2)); // Get top 2 newest

        } catch (error) {
            console.error("Dashboard Load Error", error);
        } finally {
            setLoadingMetrics(false);
        }
    };

    if (activeTab === 'home') {
        loadDashboardData();
    }
  }, [user.id, user.enrollment_status, activeTab, user.table_source]);

  const handleRestrictedTab = (tab: 'jobs' | 'for-you' | 'connect') => {
      if (metrics.completionPercentage < 100) {
          setShowRestrictionModal(true);
      } else {
          setActiveTab(tab);
      }
  };

  const NavItem = ({ id, label, icon: Icon, locked = false }: { id: string, label: string, icon: any, locked?: boolean }) => (
    <button 
      onClick={() => locked ? handleRestrictedTab(id as any) : setActiveTab(id as any)}
      className={`w-full flex items-center justify-between px-4 py-3.5 rounded-2xl transition-all duration-300 group relative overflow-hidden ${
        activeTab === id 
        ? 'bg-gradient-to-r from-luGreen to-emerald-600 text-white shadow-lg shadow-green-500/20' 
        : 'text-gray-600 hover:bg-white/50 hover:text-luGreen'
      }`}
    >
        <div className="flex items-center gap-3 relative z-10">
            <Icon size={20} className={activeTab === id ? 'text-white' : 'text-gray-400 group-hover:text-luGreen'} />
            <span className="font-bold text-sm tracking-wide">{label}</span>
        </div>
        {locked && metrics.completionPercentage < 100 && (
            <Lock size={14} className="text-gray-400/70" />
        )}
        {activeTab === id && (
            <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
        )}
    </button>
  );

  return (
    <div className="h-screen bg-[#f0f4f8] flex flex-col font-sans relative overflow-hidden text-slate-800">

      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none">
          <div className="absolute -top-[20%] -left-[10%] w-[70%] h-[70%] rounded-full bg-green-200/20 blur-[120px]"></div>
          <div className="absolute top-[20%] -right-[10%] w-[60%] h-[60%] rounded-full bg-yellow-200/20 blur-[120px]"></div>
          <div className="absolute -bottom-[10%] left-[20%] w-[50%] h-[50%] rounded-full bg-emerald-200/20 blur-[120px]"></div>
      </div>

      {/* Glass Header (Non-sticky, fixed height) */}
      <header className="flex-none z-50 px-4 pt-4">
        <div className="bg-white/70 backdrop-blur-xl border border-white/50 shadow-sm rounded-3xl px-6 py-4 flex justify-between items-center max-w-[1600px] mx-auto">

            {/* Logo */}
            <div className="flex items-center space-x-3 cursor-pointer" onClick={() => setActiveTab('home')}>
              <div className="w-10 h-10 bg-gradient-to-br from-luGreen to-emerald-600 rounded-xl flex items-center justify-center shadow-lg text-white font-display font-bold text-lg">
                 LU
              </div>
              <div className="hidden md:block">
                <h1 className="text-lg font-bold text-slate-800 tracking-tight leading-none">ALUMNI TRACER</h1>
                <p className="text-[10px] text-slate-500 font-bold tracking-widest uppercase mt-0.5">Laguna University</p>
              </div>
            </div>

            {/* Right Actions */}
            <div className="flex items-center gap-4">
              <div className="hidden md:flex items-center space-x-2 text-xs bg-emerald-50/80 backdrop-blur-md text-emerald-700 py-1.5 px-3 rounded-full border border-emerald-100/50">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
                </span>
                <span className="font-bold">System Online</span>
              </div>

              <div className="h-8 w-[1px] bg-slate-200/50 hidden md:block"></div>

              <div className="flex items-center gap-3">
                  <div className="text-right hidden sm:block">
                      <p className="text-sm font-bold text-slate-800 leading-none">{user.first_name} {user.last_name}</p>
                      <p className="text-[10px] text-slate-500 font-bold uppercase mt-0.5">{user.program}</p>
                  </div>
                  <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-slate-200 to-slate-100 border-2 border-white shadow-md flex items-center justify-center text-slate-600 font-bold">
