                        </div>

                        {/* Networking Widget - Orange Accent */}
                        <div className="bg-gradient-to-br from-orange-500 to-amber-600 p-6 rounded-[2rem] shadow-xl shadow-orange-500/20 text-white relative overflow-hidden flex flex-col justify-between min-h-[250px] border border-white/20">
                            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-3xl"></div>
                            <div className="relative z-10">
                                <div className="flex items-center gap-2 mb-4">
                                    <div className="p-2 bg-white/20 rounded-lg backdrop-blur-sm shadow-sm"><Users size={18}/></div>
                                    <span className="text-xs font-bold uppercase tracking-widest text-orange-100">Community</span>
                                </div>
                                <h3 className="text-xl font-bold mb-2">Expand Your Network</h3>
                                <p className="text-orange-50 text-xs leading-relaxed mb-6 font-medium">
                                    Connect with fellow graduates, join forums, and create groups.
                                </p>
                            </div>

                            <button 
                                onClick={() => metrics.completionPercentage < 100 ? setShowRestrictionModal(true) : setActiveTab('connect')}
                                className="w-full py-3 bg-white text-orange-600 font-bold rounded-xl shadow-lg hover:bg-orange-50 transition-colors flex items-center justify-center gap-2 text-sm relative z-10"
                            >
                                <Globe size={16}/> Go to Connect
                            </button>
                        </div>
                    </div>

                </div>
            )}

            {activeTab === 'profile' && (
                <div className="bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-xl shadow-slate-200/50 p-6 md:p-8 animate-fade-in">
                    <MyProfilePage user={user} />
                </div>
            )}

            {activeTab === 'employment' && (
                <EmploymentStatusPage user={user} />
            )}

            {activeTab === 'jobs' && (
                <div className="bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-xl shadow-slate-200/50 p-6 md:p-8 animate-fade-in">
                    <JobPostingsPage user={user} />
                </div>
            )}

            {activeTab === 'for-you' && (
                <div className="bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-xl shadow-slate-200/50 p-6 md:p-8 animate-fade-in">
                    <ForYouPage user={user} />
                </div>
            )}

            {activeTab === 'connect' && (
                <div className="bg-white/60 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-xl shadow-slate-200/50 p-6 md:p-8 animate-fade-in min-h-[600px]">
                    <ConnectPage user={user} />
                </div>
            )}

          </div>
      </main>

      {/* --- RESTRICTION MODAL --- */}
      {showRestrictionModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setShowRestrictionModal(false)}></div>
              <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20 p-8 text-center">
                  <div className="w-20 h-20 bg-amber-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner ring-8 ring-amber-50/50">
                      <Lock className="w-10 h-10 text-amber-500" />
                  </div>
                  <h3 className="text-2xl font-black text-gray-800 mb-2">Feature Locked</h3>
                  <p className="text-gray-500 text-sm mb-8 leading-relaxed">
                      This feature is reserved for active alumni with a complete profile. Please reach <strong>100% Profile Completion</strong> to access the network and job board.
                  </p>

                  <div className="space-y-3">
                      <button 
                          onClick={() => { setShowRestrictionModal(false); setActiveTab('profile'); }}
                          className="w-full py-4 bg-luGreen text-white font-bold rounded-2xl shadow-lg hover:bg-luGreen-dark transition-all text-sm flex items-center justify-center gap-2 hover:-translate-y-1"
                      >
                          Complete My Profile
                      </button>
                      <button 
                          onClick={() => setShowRestrictionModal(false)}
                          className="w-full py-4 bg-gray-100 text-gray-600 font-bold rounded-2xl hover:bg-gray-200 transition-colors text-sm"
                      >
                          Close
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* --- LOGOUT CONFIRMATION MODAL --- */}
      {showLogoutModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setShowLogoutModal(false)}></div>
              <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-sm relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20 p-8 text-center">
                  <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner ring-8 ring-red-50/50">
                      <LogOut className="w-8 h-8 text-red-500 ml-1" />
                  </div>
                  <h3 className="text-2xl font-black text-gray-800 mb-2">Sign Out?</h3>
                  <p className="text-gray-500 text-sm mb-8 leading-relaxed">
                      Are you sure you want to end your session? You will need to log in again to access your dashboard.
                  </p>

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setShowLogoutModal(false)}
                          className="flex-1 py-3 bg-gray-100 text-gray-700 font-bold rounded-xl hover:bg-gray-200 transition-colors text-sm"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={onLogout}
                          className="flex-1 py-3 bg-red-500 text-white font-bold rounded-xl shadow-lg shadow-red-200 hover:bg-red-600 transition-all text-sm"
                      >
                          Yes, Log Out
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

export default Dashboard;
